files.main.tf:
# Wurzel-Konfiguration der Expeditions-Flotte.
# Statt jeden Anleger einzeln zu beschreiben, rufen wir EINEN Baustein
# (das Modul "anleger") mehrfach mit unterschiedlichen Werten auf.

module "nordanleger" {
  source = "./modules/anleger"

  name   = "nord"
  laenge = 12
}

module "suedanleger" {
  source = "./modules/anleger"

  name   = "sued"
  laenge = 8
}

# Das Modul reicht seine Outputs nach oben durch – hier wird die fertige
# Adresse des Nordanlegers zur Ausgabe der Wurzel-Konfiguration.
output "nordanleger_adresse" {
  value = module.nordanleger.adresse
}

files.modules/anleger/variables.tf:
# Eingabe-Variablen des Bausteins: das, was der Aufrufer von außen setzt.

variable "name" {
  description = "Name des Anlegers (z. B. nord, sued)."
  type        = string
}

variable "laenge" {
  description = "Länge des Kais in Metern."
  type        = number
  default     = 10
}

files.modules/anleger/main.tf:
# Die Ressourcen, die der Baustein als Einheit erzeugt.

resource "hafen_kai" "kai" {
  name   = var.name
  laenge = var.laenge
}

resource "hafen_poller" "poller" {
  kai    = hafen_kai.kai.name
  anzahl = 4
}

files.modules/anleger/outputs.tf:
# Was der Baustein nach außen sichtbar macht.

output "adresse" {
  description = "Die fertige Anleger-Adresse im Hafennetz."
  value       = "${var.name}-kai.flotte.local"
}

files.backend.tf:
# Der State – Terraforms Gedächtnis – soll nicht lokal auf einem Laptop liegen,
# sondern zentral im "Flotten-Lager", damit die ganze Crew denselben Stand sieht.
terraform {
  backend "s3" {
    bucket         = "flotten-lager"
    key            = "flotte/terraform.tfstate"
    region         = "kubernia-nord"
    dynamodb_table = "flotten-schloss" # State-Locking: nur EINE Crew darf zugleich ändern
  }
}

files.main.tf:
# Eine Flotten-Ressource, deren Stand künftig im Flotten-Lager liegt.
resource "hafen_leuchtfeuer" "einfahrt" {
  name       = "einfahrt-nord"
  reichweite = 30
}

files.provider.tf:
# Die Flotte expandiert auf ZWEI Inseln verschiedener Anbieter (Multi-Cloud).
# Jeder Anbieter braucht seinen eigenen provider-Block – terraform init lädt beide.
terraform {
  required_providers {
    nordwind = {
      source  = "kubequest/nordwind"
      version = "1.4.0"
    }
    passat = {
      source  = "kubequest/passat"
      version = "0.9.2"
    }
  }
}

provider "nordwind" {
  region = "nord-see"
}

provider "passat" {
  region = "sued-see"
}

files.main.tf:
# Je eine Insel bei jedem Anbieter. Über provider = … wählen wir den Anbieter aus.
resource "nordwind_insel" "ost" {
  provider = nordwind
  name     = "ost-vorposten"
}

resource "passat_insel" "west" {
  provider = passat
  name     = "west-vorposten"
}

files.variables.tf:
# Eingabe-Variablen: zentrale Stellschrauben statt fest verdrahteter Werte.

variable "flotten_name" {
  description = "Name der Flotte."
  type        = string
  default     = "kubernia-expedition"
}

variable "schiffe" {
  description = "Anzahl der Schiffe in der Flotte."
  type        = number
  default     = 5
}

variable "lager_schluessel" {
  description = "Zugangsschlüssel zum Flotten-Lager (geheim!)."
  type        = string
  sensitive   = true
}

files.main.tf:
# Die Ressource nutzt die Variablen – nichts ist hier fest verdrahtet.
resource "hafen_flotte" "expedition" {
  name    = var.flotten_name
  schiffe = var.schiffe
}

files.outputs.tf:
# Outputs: berechnete Werte sauber nach außen geben.

output "flotten_groesse" {
  description = "Wie viele Schiffe die Flotte zählt."
  value       = var.schiffe
}

output "anleger_adresse" {
  description = "Adresse des Flotten-Anlegers im Hafennetz."
  value       = "${var.flotten_name}.flotte.local"
}

output "lager_schluessel" {
  description = "Der geheime Lager-Schlüssel – wird verborgen ausgegeben."
  value       = var.lager_schluessel
  sensitive   = true
}
